/// An individual metric Forecast calculated when monitoring predictor usage.
/// You can compare the value for this metric to the metric's value in the
/// Baseline to see how your predictor's performance is changing.
///
/// For more information about metrics generated by Forecast see [Evaluating
/// Predictor
/// Accuracy](https://docs.aws.amazon.com/forecast/latest/dg/metrics.html)
pub const MetricResult = struct {
    /// The name of the metric.
    metric_name: ?[]const u8 = null,

    /// The value for the metric.
    metric_value: ?f64 = null,

    pub const json_field_names = .{
        .metric_name = "MetricName",
        .metric_value = "MetricValue",
    };
};
